RISKS:
[
 {
  "riskId": "risk.structure-independence.framework-foreclosure-large-operator-cell",
  "title": "Global framework agreements dissolve the 'large operator direct' cell the venture plans to enter first",
  "claim": "The funnel counts 40% of PDU spend as 'large operators' — the venture's declared first buyer. But the number is a capacity-share proxy, not a channel reality. The documented procurement pattern for exactly these buyers is HQ-level global frameworks and integrator bundles: pan-European colos and hyperscalers sign multi-year power-chain packages with Schneider/Vertiv-class suppliers or take PDUs embedded in OEM/ODM rack builds. A regional entrant never sees an RFP for that spend. The cell exists as consumption; it barely exists as a contestable transaction. The independence assumption geography × segment × buyer hides that the biggest buyer cell and the least reachable procurement route are the same cell.",
  "falsifier": "Three CE large operators confirming they run discrete, vendor-open rack-PDU RFPs (not framework call-offs or integrator bundles) for their 2026 fit-outs."
 },
 {
  "riskId": "risk.structure-independence.colo-weights-enterprise-slice-misallocation",
  "title": "Colo-MW geography weights are wrong by construction for the 29% enterprise slice — the Netherlands cell is partly phantom",
  "claim": "Every geo share was apportioned on Statista colocation MW, but the segment axis includes 29% enterprise on-premise demand — and enterprise machine rooms are distributed by industrial base, not by where Amsterdam colo campuses stand. EUDCA's own framing says colo+hyperscale is only about two-thirds of Europe's IT power; the missing third has a different map. NL is the most colo-concentrated market in the set (~70% of its capacity in Amsterdam metro), while Switzerland is self-operation-heavy (installed-base method gives 0.13 vs the curated 0.08) and Germany's installed load exceeds its colo figure by ~1,000MW. Multiplying colo-weighted geography by an enterprise segment share manufactures enterprise PDU demand in the Netherlands that physically sits in German and Swiss machine rooms. Anyone sizing a DACH enterprise channel off these weights will staff the wrong countries.",
  "falsifier": "A consistent country-level installed-IT-load table (e.g., EUDCA country profiles) showing NL's share of CE-7 total installed load ≈ its colo share (~0.28) — i.e., the non-colo third distributes the same way the colo two-thirds does."
 },
 {
  "riskId": "risk.structure-independence.ce-hyperscale-global-split-mirage",
  "title": "The DE×hyperscale anchor cell is a mirage: CE-7's hyperscale-owned share is far below the rescaled global 44%",
  "claim": "seg.hyperscale rescales Synergy's global 48% flat onto Central Europe. But ~60% of Europe's operational hyperscaler self-build capacity sits in Ireland, the Netherlands, Sweden and Belgium — three of the four outside CE-7. Inside CE, hyperscale presence is mostly leased capacity inside Frankfurt and Amsterdam colo campuses, which Statista's 'colocation and scale colocation' figure already counts on the geography axis as colo MW. The cube therefore double-books the same megawatts — hyperscale on the segment axis, colo on the geo axis — and the implied beachhead cell (DE 0.50 × hyperscale 0.44 ≈ 22% of TAM as 'German hyperscale') largely does not exist as hyperscale-owned facilities. The real buyer of that capacity's PDUs is the colo operator or its integrator, with colo-grade requirements: tenant billing metering, multi-tenant DCIM. A product roadmap and sales motion built for hyperscale custom SKUs in Germany aims at a cell the market never populated.",
  "falsifier": "A Europe- or CE-scoped capacity split (Synergy, CBRE or JLL) showing hyperscale-owned/self-build capacity ≥40% of CE-7 total — i.e., the global split does transfer."
 },
 {
  "riskId": "risk.structure-independence.stock-weighted-tam-misses-fitout-flow",
  "title": "TAM is apportioned on capacity stock, but PDU revenue follows fit-out flow — and the flow is concentrating outside CE-7",
  "claim": "The €300M base scopes Europe down to CE-7 using 39.8% of Europe's colocation MW stock. But PDUs are bought at fit-out: revenue tracks new capacity delivered plus refresh, not standing stock. Europe's new-supply flow is heavily skewed — 57% of 2025's 937MW of new colo supply and 85% of take-up land in FLAPD, of which only Frankfurt and Amsterdam are CE-7; the UK alone (1,772MW, Europe's largest market) plus Paris, Dublin and fast-growing secondary markets like Milan and Madrid sit entirely outside the denominator's numerator. If CE-7's share of European fit-out flow is meaningfully below its 39.8% stock share, the €300M base is biased high in a way the 240–360 band — built from global-anchor and FX uncertainty — was never designed to cover.",
  "falsifier": "A vendor-share or shipment-based regional table (e.g., the pending Omdia vendor table or IndexBox EU country tables) showing CE-7 at ≈38–40% of European rack-PDU revenue — matching the stock share."
 },
 {
  "riskId": "risk.structure-independence.frankfurt-cycle-lockout-year1",
  "title": "Buyer concentration × procurement timing empties the Year-1 window in the exact cell the ramp assumes",
  "claim": "The 1%-of-SAM Year-1 benchmark implicitly assumes demand arrives smoothly from many independent buyers. But the venture's chosen cell — DE-heavy geography (0.50) times large operators (0.40) — is the lumpiest corner of the cube: a handful of Frankfurt/Amsterdam campus fit-outs whose electrical BoM, PDUs included, is specified at design and tender stage long before delivery. Capacity delivering in the venture's first 12 months was specced in 2024–25; capacity being specced now delivers after the window closes. The correlation between concentration and procurement timing means the truly contestable slice of SAM in months 0–12 is far below what a market-average benchmark implies — the YAM can miss even at the band's low end without a single node being 'wrong'.",
  "falsifier": "Two or more CE large-operator rack-PDU procurements in the venture's first 12 months that are open to unlisted vendors and run from RFQ to award to delivery inside that same window."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
